PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?episodeLabel ?season ?airdate WHERE {
  ?episode wdt:P179 wd:Q438406;  
           wdt:P31 wd:Q21191270;
           wdt:P674 wd:Q28668528;
           wdt:P659 ?season;
           wdt:P577 ?airdate.
  FILTER (?airdate < NOW())
  SERVICE <http://wikiba.se/ontology#label> {
    ?episode rdfs:label ?episodeLabel.
    FILTER(LANG(?episodeLabel) = 'en')
  }
}
ORDER BY ?airdate
LIMIT 1

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?episodeLabel ?airdate WHERE {
  ?episode wdt:P179 wd:Q438406;
         wdt:P577 ?airdate;
         wdt:P161 wd:Q269900.
  ?episode rdfs:label ?episodeLabel.
  FILTER(LANG(?episodeLabel) = "en")
}
ORDER BY ?airdate
LIMIT 1
